import { useState, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Checkbox } from "@/components/ui/checkbox";
import { useToast } from "@/hooks/use-toast";
import { useSessionStorageState } from "@/hooks/useSessionStorageState";
import {
  Zap, Loader2, RotateCcw, Play, Globe, ChevronDown, ChevronRight,
  MapPin, CheckCircle2, XCircle, Clock, Search, Landmark, ArrowDownToLine,
  Plus, Square, Filter, RefreshCw, AlertTriangle, Pause,
} from "lucide-react";
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table";

interface CityTask {
  city: string;
  status: string;
  discovered_count: number;
  imported_count: number;
  error_message: string | null;
  started_at: string | null;
  completed_at: string | null;
}

interface CountryGroup {
  total: number;
  pending: number;
  processing: number;
  completed: number;
  failed: number;
  discovered: number;
  imported: number;
  cities: CityTask[];
}

interface PipelineStatus {
  total: number;
  pending: number;
  processing: number;
  completed: number;
  failed: number;
  total_discovered: number;
  total_imported: number;
  by_country?: Record<string, CountryGroup>;
  processing_now?: { city: string; country_code: string; started_at: string | null }[];
  recently_completed?: { city: string; country_code: string; discovered_count: number; imported_count: number; completed_at: string | null }[];
  failed_tasks?: { city: string; country_code: string; error_message: string | null }[];
}

const COUNTRY_NAMES: Record<string, string> = {
  PT: "🇵🇹 葡萄牙", ES: "🇪🇸 西班牙", FR: "🇫🇷 法国", DE: "🇩🇪 德国",
  IT: "🇮🇹 意大利", GB: "🇬🇧 英国", NL: "🇳🇱 荷兰", HU: "🇭🇺 匈牙利",
  JP: "🇯🇵 日本", KR: "🇰🇷 韩国", CN: "🇨🇳 中国", TW: "🇹🇼 台湾",
  TH: "🇹🇭 泰国", VN: "🇻🇳 越南", SG: "🇸🇬 新加坡", MY: "🇲🇾 马来西亚",
  ID: "🇮🇩 印尼", PH: "🇵🇭 菲律宾", IN: "🇮🇳 印度",
  US: "🇺🇸 美国", CA: "🇨🇦 加拿大", MX: "🇲🇽 墨西哥", BR: "🇧🇷 巴西",
  AR: "🇦🇷 阿根廷", CL: "🇨🇱 智利", CO: "🇨🇴 哥伦比亚", PE: "🇵🇪 秘鲁",
  AE: "🇦🇪 阿联酋", SA: "🇸🇦 沙特", EG: "🇪🇬 埃及", ZA: "🇿🇦 南非",
  MA: "🇲🇦 摩洛哥", KE: "🇰🇪 肯尼亚", NG: "🇳🇬 尼日利亚", IL: "🇮🇱 以色列",
  TR: "🇹🇷 土耳其", GH: "🇬🇭 加纳",
  AU: "🇦🇺 澳大利亚", NZ: "🇳🇿 新西兰",
};

const REGIONS: { key: string; label: string; emoji: string; seedRegion?: string }[] = [
  { key: "europe", label: "欧洲", emoji: "🇪🇺" },
  { key: "asia", label: "亚洲", emoji: "🌏", seedRegion: "asia" },
  { key: "americas", label: "美洲", emoji: "🌎", seedRegion: "americas" },
  { key: "middle_east_africa", label: "中东/非洲", emoji: "🌍", seedRegion: "middle_east_africa" },
  { key: "oceania", label: "大洋洲", emoji: "🌊", seedRegion: "oceania" },
];

const REGION_COUNTRIES: Record<string, string[]> = {
  europe: ["PT", "ES", "FR", "DE", "IT", "GB", "NL", "HU"],
  asia: ["JP", "KR", "CN", "HK", "TW", "TH", "VN", "SG", "MY", "ID", "PH", "IN"],
  americas: ["US", "CA", "MX", "BR", "AR", "CL", "CO", "PE"],
  middle_east_africa: ["AE", "SA", "TR", "EG", "MA", "ZA", "KE", "NG", "IL", "GH"],
  oceania: ["AU", "NZ"],
};

function getCountryName(code: string) {
  return COUNTRY_NAMES[code] || `🏳️ ${code}`;
}

function timeAgo(dateStr: string | null) {
  if (!dateStr) return "";
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "刚刚";
  if (mins < 60) return `${mins}分钟前`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}小时前`;
  return `${Math.floor(hrs / 24)}天前`;
}

function getRegionForCountry(code: string): string {
  for (const [region, countries] of Object.entries(REGION_COUNTRIES)) {
    if (countries.includes(code)) return region;
  }
  return "other";
}

export default function DiscoveryPipelineDashboard() {
  const { toast } = useToast();
  const [status, setStatus] = useState<PipelineStatus | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isAutoRefresh, setIsAutoRefresh] = useState(false);
  const [expandedRegionKeys, setExpandedRegionKeys] = useSessionStorageState<string[]>("admin-discover-restaurants:pipeline-expanded-regions", []);
  const [expandedCountryKeys, setExpandedCountryKeys] = useSessionStorageState<string[]>("admin-discover-restaurants:pipeline-expanded-countries", []);
  const [selectedCountryKeys, setSelectedCountryKeys] = useSessionStorageState<string[]>("admin-discover-restaurants:pipeline-selected-countries", []);
  const [showCountryPicker, setShowCountryPicker] = useSessionStorageState<string | null>("admin-discover-restaurants:pipeline-country-picker", null);
  const [showActivityLog, setShowActivityLog] = useSessionStorageState("admin-discover-restaurants:pipeline-activity-log", false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const expandedRegions = new Set(expandedRegionKeys);
  const expandedCountries = new Set(expandedCountryKeys);
  const selectedCountries = new Set(selectedCountryKeys);

  const fetchStatus = async () => {
    try {
      const { data } = await supabase.functions.invoke("auto-discover-restaurants", {
        body: { action: "status" },
      });
      if (data) setStatus(data);
    } catch (e) {
      console.error("Status fetch error:", e);
    }
  };

  useEffect(() => { fetchStatus(); }, []);

  useEffect(() => {
    if (isAutoRefresh) {
      intervalRef.current = setInterval(fetchStatus, 10000);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [isAutoRefresh]);

  useEffect(() => {
    if (status && status.processing > 0 && !isAutoRefresh) {
      setIsAutoRefresh(true);
    }
  }, [status?.processing]);

  const toggleCountrySelection = (code: string) => {
    setSelectedCountryKeys(prev => {
      const next = new Set(prev);
      next.has(code) ? next.delete(code) : next.add(code);
      return [...next];
    });
  };

  const selectAllInRegion = (regionKey: string) => {
    const codes = REGION_COUNTRIES[regionKey] || [];
    setSelectedCountryKeys(prev => {
      const next = new Set(prev);
      const allSelected = codes.every(c => next.has(c));
      if (allSelected) codes.forEach(c => next.delete(c));
      else codes.forEach(c => next.add(c));
      return [...next];
    });
  };

  const handleSeed = async (region?: string, countries?: string[]) => {
    setIsLoading(true);
    try {
      const body: any = { action: "seed" };
      if (countries && countries.length > 0) body.countries = countries;
      else if (region) body.region = region;
      const { data, error } = await supabase.functions.invoke("auto-discover-restaurants", { body });
      if (error) throw error;
      toast({ title: "✅ 已添加到队列", description: `${data.seeded} 个城市即将开始搜索` });
      setSelectedCountryKeys([]);
      setShowCountryPicker(null);
      await fetchStatus();
    } catch (e) {
      toast({ title: "错误", description: String(e), variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = async () => {
    setIsLoading(true);
    try {
      await supabase.functions.invoke("auto-discover-restaurants", { body: { action: "reset" } });
      toast({ title: "已重置", description: "失败任务已重新排队" });
      await fetchStatus();
    } catch (e) {
      toast({ title: "错误", description: String(e), variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleRunNow = async () => {
    setIsLoading(true);
    setIsAutoRefresh(true);
    try {
      const { data, error } = await supabase.functions.invoke("auto-discover-restaurants", {
        body: { action: "run", batch_size: 2 },
      });
      if (error) throw error;
      toast({ title: "✅ 手动运行完成", description: `处理了 ${data.processed} 个城市` });
      await fetchStatus();
    } catch (e) {
      toast({ title: "错误", description: String(e), variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleStop = async (region?: string) => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke("auto-discover-restaurants", {
        body: { action: "stop", region: region || undefined },
      });
      if (error) throw error;
      toast({ title: "⏹ 已停止", description: `已取消 ${data?.cancelled || 0} 个排队任务` });
      await fetchStatus();
    } catch (e) {
      toast({ title: "错误", description: String(e), variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  const progressPercent = status && status.total > 0
    ? Math.round((status.completed / status.total) * 100) : 0;

  const byCountry = status?.by_country || {};
  const processingNow = status?.processing_now || [];
  const recentlyCompleted = status?.recently_completed || [];
  const failedTasks = status?.failed_tasks || [];

  const getRegionStats = (regionKey: string) => {
    const countryCodes = REGION_COUNTRIES[regionKey] || [];
    let total = 0, completed = 0, pending = 0, processing = 0, failed = 0, discovered = 0, imported = 0;
    const countries: [string, CountryGroup][] = [];

    for (const code of countryCodes) {
      const group = byCountry[code];
      if (group) {
        total += group.total; completed += group.completed; pending += group.pending;
        processing += group.processing; failed += group.failed;
        discovered += group.discovered; imported += group.imported;
        countries.push([code, group]);
      }
    }
    for (const [code, group] of Object.entries(byCountry)) {
      if (getRegionForCountry(code) === regionKey && !countryCodes.includes(code)) {
        total += group.total; completed += group.completed; pending += group.pending;
        processing += group.processing; failed += group.failed;
        discovered += group.discovered; imported += group.imported;
        countries.push([code, group]);
      }
    }
    return { total, completed, pending, processing, failed, discovered, imported, countries };
  };

  return (
    <div className="space-y-4">
      {/* ── Top Stats Row ── */}
      <div className="grid grid-cols-2 md:grid-cols-6 gap-3">
        <PipelineStatCard
          icon={<Globe className="h-4 w-4" />}
          label="总城市"
          value={status?.total || 0}
        />
        <PipelineStatCard
          icon={<Clock className="h-4 w-4 text-yellow-500" />}
          label="排队中"
          value={status?.pending || 0}
          highlight={status?.pending ? "yellow" : undefined}
        />
        <PipelineStatCard
          icon={<Search className="h-4 w-4 text-blue-500" />}
          label="搜索中"
          value={status?.processing || 0}
          highlight={status?.processing ? "blue" : undefined}
        />
        <PipelineStatCard
          icon={<CheckCircle2 className="h-4 w-4 text-emerald-500" />}
          label="已完成"
          value={status?.completed || 0}
          highlight="green"
        />
        <PipelineStatCard
          icon={<Landmark className="h-4 w-4 text-purple-500" />}
          label="发现"
          value={status?.total_discovered || 0}
        />
        <PipelineStatCard
          icon={<ArrowDownToLine className="h-4 w-4 text-emerald-500" />}
          label="导入"
          value={status?.total_imported || 0}
        />
      </div>

      {/* ── Progress + Actions Bar ── */}
      <Card>
        <CardContent className="py-3 px-4">
          <div className="flex items-center gap-3">
            {/* Progress section */}
            <div className="flex-1 min-w-0">
              {status && status.total > 0 ? (
                <div className="space-y-1.5">
                  <div className="flex items-center justify-between text-xs">
                    <div className="flex items-center gap-2">
                      {status.processing > 0 && (
                        <Badge className="bg-blue-500 text-white text-[10px] animate-pulse">
                          <Loader2 className="h-2.5 w-2.5 mr-0.5 animate-spin" /> 运行中
                        </Badge>
                      )}
                      {status.processing === 0 && status.pending > 0 && (
                        <Badge variant="secondary" className="text-[10px]">
                          <Pause className="h-2.5 w-2.5 mr-0.5" /> 等待自动运行
                        </Badge>
                      )}
                      {status.pending === 0 && status.processing === 0 && status.failed === 0 && (
                        <Badge variant="secondary" className="text-[10px] bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400">
                          <CheckCircle2 className="h-2.5 w-2.5 mr-0.5" /> 全部完成
                        </Badge>
                      )}
                      <span className="text-muted-foreground font-mono">{status.completed}/{status.total} 城市</span>
                    </div>
                    <span className="font-mono font-bold text-foreground">{progressPercent}%</span>
                  </div>
                  <Progress value={progressPercent} className="h-2" />
                </div>
              ) : (
                <p className="text-sm text-muted-foreground">还没有任务。选择区域开始自动发现。</p>
              )}
            </div>

            {/* Actions */}
            <div className="flex items-center gap-1.5 shrink-0">
              <Button
                size="sm" variant="outline"
                onClick={handleRunNow}
                disabled={isLoading || !status?.pending}
                className="h-8 text-xs"
              >
                {isLoading ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : <Play className="h-3 w-3 mr-1" />}
                运行一批
              </Button>
              {(status?.failed || 0) > 0 && (
                <Button size="sm" variant="outline" onClick={handleReset} disabled={isLoading} className="h-8 text-xs">
                  <RotateCcw className="h-3 w-3 mr-1" /> 重试失败 ({status?.failed})
                </Button>
              )}
              {(status?.pending || 0) > 0 && (
                <Button
                  size="sm" variant="outline"
                  onClick={() => handleStop()}
                  disabled={isLoading}
                  className="h-8 text-xs text-destructive border-destructive/30 hover:bg-destructive/10"
                >
                  <Square className="h-3 w-3 mr-1 fill-current" /> 全部停止
                </Button>
              )}
              <div className="w-px h-5 bg-border mx-0.5" />
              <Button
                size="sm"
                variant={isAutoRefresh ? "default" : "ghost"}
                onClick={() => setIsAutoRefresh(!isAutoRefresh)}
                className="h-8 text-xs"
              >
                {isAutoRefresh ? <Loader2 className="h-3 w-3 animate-spin" /> : <RefreshCw className="h-3 w-3" />}
              </Button>
              <Button size="sm" variant="ghost" onClick={fetchStatus} className="h-8 text-xs">
                <RotateCcw className="h-3 w-3" />
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* ── Live Processing Banner ── */}
      {processingNow.length > 0 && (
        <div className="rounded-lg border border-blue-200 dark:border-blue-800 bg-blue-50/50 dark:bg-blue-950/20 px-4 py-3">
          <div className="flex items-center gap-2 text-xs font-medium text-blue-700 dark:text-blue-400 mb-2">
            <Loader2 className="h-3.5 w-3.5 animate-spin" />
            正在搜索 {processingNow.length} 个城市
          </div>
          <div className="flex flex-wrap gap-2">
            {processingNow.map((p, i) => (
              <Badge key={i} variant="outline" className="border-blue-300 dark:border-blue-700 text-blue-700 dark:text-blue-300 text-xs">
                {getCountryName(p.country_code)} · {p.city}
                {p.started_at && <span className="text-[10px] ml-1 opacity-60">{timeAgo(p.started_at)}</span>}
              </Badge>
            ))}
          </div>
        </div>
      )}

      {/* ── Region Table ── */}
      <Card>
        <CardHeader className="pb-2 px-4 pt-4">
          <div className="flex items-center justify-between">
            <CardTitle className="text-sm flex items-center gap-2">
              <MapPin className="h-4 w-4 text-primary" />
              区域与国家
            </CardTitle>
            <Button size="sm" variant="outline" onClick={() => handleSeed('global')} disabled={isLoading} className="h-7 text-xs">
              <Globe className="h-3 w-3 mr-1" /> 全球一键添加
            </Button>
          </div>
        </CardHeader>
        <CardContent className="px-0 pb-0">
          <div className="divide-y">
            {REGIONS.map(region => {
              const stats = getRegionStats(region.key);
              const seeded = stats.total > 0;
              const regionProgress = stats.total > 0 ? Math.round((stats.completed / stats.total) * 100) : 0;
              const isExpanded = expandedRegions.has(region.key);

              return (
                <div key={region.key}>
                  {/* Region Row */}
                  <div className="flex items-center gap-3 px-4 py-2.5 hover:bg-muted/30 transition-colors">
                    <button
                      className="flex items-center gap-2 flex-1 min-w-0 text-left"
                      onClick={() => {
                        setExpandedRegionKeys(prev => {
                          const next = new Set(prev);
                          next.has(region.key) ? next.delete(region.key) : next.add(region.key);
                          return [...next];
                        });
                      }}
                      disabled={!seeded}
                    >
                      {seeded ? (
                        isExpanded ? <ChevronDown className="h-3.5 w-3.5 text-muted-foreground shrink-0" /> : <ChevronRight className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
                      ) : (
                        <div className="h-3.5 w-3.5 shrink-0" />
                      )}
                      <span className="text-base">{region.emoji}</span>
                      <span className="font-medium text-sm">{region.label}</span>
                      {stats.processing > 0 && (
                        <Badge className="bg-blue-500 text-white text-[9px] h-4 animate-pulse ml-1">搜索中</Badge>
                      )}
                    </button>

                    {/* Stats inline */}
                    {seeded && (
                      <div className="flex items-center gap-3 text-xs text-muted-foreground shrink-0">
                        <div className="w-24 hidden sm:block">
                          <div className="h-1.5 w-full bg-muted rounded-full overflow-hidden">
                            <div
                              className={`h-full rounded-full transition-all ${stats.processing > 0 ? 'bg-blue-500' : regionProgress === 100 ? 'bg-emerald-500' : 'bg-primary'}`}
                              style={{ width: `${regionProgress}%` }}
                            />
                          </div>
                        </div>
                        <span className="font-mono w-12 text-right">{regionProgress}%</span>
                        <span className="font-mono w-16 text-right">{stats.completed}/{stats.total}</span>
                        {stats.discovered > 0 && <span className="text-purple-600 dark:text-purple-400 w-14 text-right">🏛 {stats.discovered}</span>}
                        {stats.imported > 0 && <span className="text-emerald-600 dark:text-emerald-400 w-14 text-right">📥 {stats.imported}</span>}
                        {stats.failed > 0 && <span className="text-destructive w-10 text-right">❌ {stats.failed}</span>}
                      </div>
                    )}

                    {/* Actions */}
                    <div className="flex items-center gap-1 shrink-0">
                      {(stats.pending > 0 || stats.processing > 0) && (
                        <Button size="sm" variant="ghost" onClick={() => handleStop(region.key)} disabled={isLoading} className="h-6 w-6 p-0 text-destructive hover:bg-destructive/10">
                          <Square className="h-3 w-3 fill-current" />
                        </Button>
                      )}
                      <Button
                        size="sm" variant="ghost"
                        onClick={(e) => { e.stopPropagation(); setShowCountryPicker(showCountryPicker === region.key ? null : region.key); }}
                        disabled={isLoading}
                        className="h-6 w-6 p-0"
                      >
                        <Filter className="h-3 w-3" />
                      </Button>
                      {!seeded && (
                        <Button size="sm" onClick={() => handleSeed(region.seedRegion)} disabled={isLoading} className="h-7 text-xs">
                          {isLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <Plus className="h-3 w-3 mr-1" />}
                          添加
                        </Button>
                      )}
                    </div>
                  </div>

                  {/* Country Picker */}
                  {showCountryPicker === region.key && (
                    <div className="px-4 py-3 bg-muted/20 border-t space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-xs text-muted-foreground">选择要搜索的国家：</span>
                        <Button size="sm" variant="ghost" className="h-5 text-[10px] px-1.5" onClick={() => selectAllInRegion(region.key)}>
                          {(REGION_COUNTRIES[region.key] || []).every(c => selectedCountries.has(c)) ? "取消全选" : "全选"}
                        </Button>
                      </div>
                      <div className="flex flex-wrap gap-1.5">
                        {(REGION_COUNTRIES[region.key] || []).map(code => (
                          <label
                            key={code}
                            className={`inline-flex items-center gap-1.5 text-xs px-2.5 py-1.5 rounded-md border cursor-pointer transition-colors ${
                              selectedCountries.has(code)
                                ? 'border-primary bg-primary/10 text-foreground'
                                : 'border-muted hover:bg-muted/50 text-muted-foreground'
                            }`}
                          >
                            <Checkbox checked={selectedCountries.has(code)} onCheckedChange={() => toggleCountrySelection(code)} className="h-3.5 w-3.5" />
                            {getCountryName(code)}
                          </label>
                        ))}
                      </div>
                      {selectedCountries.size > 0 && (
                        <Button
                          size="sm"
                          onClick={() => {
                            const regionCodes = REGION_COUNTRIES[region.key] || [];
                            const selected = [...selectedCountries].filter(c => regionCodes.includes(c));
                            handleSeed(undefined, selected);
                          }}
                          disabled={isLoading}
                          className="h-7 text-xs"
                        >
                          {isLoading ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : <Search className="h-3 w-3 mr-1" />}
                          搜索选中 {[...selectedCountries].filter(c => (REGION_COUNTRIES[region.key] || []).includes(c)).length} 个国家
                        </Button>
                      )}
                    </div>
                  )}

                  {/* Expanded: country table */}
                  {seeded && isExpanded && (
                    <div className="bg-muted/10">
                      <Table>
                        <TableHeader>
                          <TableRow className="text-[11px]">
                            <TableHead className="h-7 pl-10">国家</TableHead>
                            <TableHead className="h-7 w-24">进度</TableHead>
                            <TableHead className="h-7 w-16 text-right">城市</TableHead>
                            <TableHead className="h-7 w-16 text-right">发现</TableHead>
                            <TableHead className="h-7 w-16 text-right">导入</TableHead>
                            <TableHead className="h-7 w-16 text-right">状态</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {stats.countries
                            .sort((a, b) => {
                              if (a[1].processing > 0 && b[1].processing === 0) return -1;
                              if (b[1].processing > 0 && a[1].processing === 0) return 1;
                              return (b[1].completed / Math.max(b[1].total, 1)) - (a[1].completed / Math.max(a[1].total, 1));
                            })
                            .map(([code, group]) => {
                              const cp = group.total > 0 ? Math.round((group.completed / group.total) * 100) : 0;
                              const active = group.processing > 0;
                              const isCountryExpanded = expandedCountries.has(code);

                              return (
                                <TableRow
                                  key={code}
                                  className={`text-xs cursor-pointer hover:bg-muted/30 ${active ? 'bg-blue-50/30 dark:bg-blue-950/10' : ''}`}
                                  onClick={() => {
                                      setExpandedCountryKeys(prev => {
                                        const next = new Set(prev);
                                        next.has(code) ? next.delete(code) : next.add(code);
                                        return [...next];
                                      });
                                  }}
                                >
                                  <TableCell className="py-1.5 pl-10 font-medium">
                                    <div className="flex items-center gap-1.5">
                                      {isCountryExpanded ? <ChevronDown className="h-3 w-3 text-muted-foreground" /> : <ChevronRight className="h-3 w-3 text-muted-foreground" />}
                                      {getCountryName(code)}
                                      {active && <Loader2 className="h-3 w-3 text-blue-500 animate-spin" />}
                                    </div>
                                    {/* Expanded city list */}
                                    {isCountryExpanded && group.cities.length > 0 && (
                                      <div className="mt-1.5 ml-4 space-y-0.5 border-l-2 border-muted pl-3 pb-1" onClick={e => e.stopPropagation()}>
                                        {group.cities.map((city, i) => (
                                          <div key={i} className="flex items-center gap-2 text-[11px] py-0.5">
                                            {city.status === "completed" ? (
                                              <CheckCircle2 className="h-2.5 w-2.5 text-emerald-500 shrink-0" />
                                            ) : city.status === "processing" ? (
                                              <Loader2 className="h-2.5 w-2.5 text-blue-500 animate-spin shrink-0" />
                                            ) : city.status === "failed" ? (
                                              <XCircle className="h-2.5 w-2.5 text-destructive shrink-0" />
                                            ) : (
                                              <Clock className="h-2.5 w-2.5 text-muted-foreground shrink-0" />
                                            )}
                                            <span className={city.status === 'processing' ? 'font-medium text-blue-600' : ''}>
                                              {city.city}
                                            </span>
                                            {city.status === 'completed' && city.discovered_count > 0 && (
                                              <span className="text-emerald-600 dark:text-emerald-400 ml-auto">
                                                {city.discovered_count}发现 · {city.imported_count}导入
                                              </span>
                                            )}
                                            {city.status === 'completed' && city.discovered_count === 0 && (
                                              <span className="text-muted-foreground ml-auto">无结果</span>
                                            )}
                                            {city.status === 'failed' && (
                                              <span className="text-destructive truncate max-w-[200px] ml-auto" title={city.error_message || ''}>
                                                {(city.error_message || '').slice(0, 40)}
                                              </span>
                                            )}
                                          </div>
                                        ))}
                                      </div>
                                    )}
                                  </TableCell>
                                  <TableCell className="py-1.5">
                                    <div className="h-1.5 w-full bg-muted rounded-full overflow-hidden">
                                      <div
                                        className={`h-full rounded-full transition-all ${active ? 'bg-blue-500' : cp === 100 ? 'bg-emerald-500' : 'bg-primary'}`}
                                        style={{ width: `${cp}%` }}
                                      />
                                    </div>
                                  </TableCell>
                                  <TableCell className="py-1.5 text-right font-mono text-muted-foreground">{group.completed}/{group.total}</TableCell>
                                  <TableCell className="py-1.5 text-right font-mono text-purple-600 dark:text-purple-400">{group.discovered || '-'}</TableCell>
                                  <TableCell className="py-1.5 text-right font-mono text-emerald-600 dark:text-emerald-400">{group.imported || '-'}</TableCell>
                                  <TableCell className="py-1.5 text-right">
                                    {group.failed > 0 && <Badge variant="destructive" className="text-[9px] h-4 px-1">{group.failed}失败</Badge>}
                                    {group.failed === 0 && cp === 100 && <CheckCircle2 className="h-3.5 w-3.5 text-emerald-500 inline" />}
                                    {group.failed === 0 && cp < 100 && group.pending > 0 && <span className="text-muted-foreground text-[10px]">⏳{group.pending}</span>}
                                  </TableCell>
                                </TableRow>
                              );
                            })}
                        </TableBody>
                      </Table>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* ── Activity Log (collapsible) ── */}
      <Card>
        <CardHeader
          className="pb-2 px-4 pt-3 cursor-pointer hover:bg-muted/30 transition-colors"
          onClick={() => setShowActivityLog(!showActivityLog)}
        >
          <div className="flex items-center justify-between">
            <CardTitle className="text-sm flex items-center gap-2">
              {showActivityLog ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
              📋 搜索记录
              {recentlyCompleted.length > 0 && (
                <Badge variant="secondary" className="text-[10px] h-4 px-1.5">{recentlyCompleted.length}</Badge>
              )}
              {failedTasks.length > 0 && (
                <Badge variant="destructive" className="text-[10px] h-4 px-1.5">{failedTasks.length} 失败</Badge>
              )}
            </CardTitle>
            <span className="text-[10px] text-muted-foreground">系统每10分钟自动处理一批</span>
          </div>
        </CardHeader>
        {showActivityLog && (
          <CardContent className="px-4 pb-3 pt-0">
            {recentlyCompleted.length > 0 ? (
              <ScrollArea className="max-h-[300px]">
                <div className="space-y-0.5">
                  {recentlyCompleted.map((item, i) => (
                    <div key={i} className="flex items-center gap-2 text-xs py-1.5 px-2 rounded hover:bg-muted/30">
                      <CheckCircle2 className="h-3 w-3 text-emerald-500 shrink-0" />
                      <span className="font-medium">{getCountryName(item.country_code)}</span>
                      <span className="text-muted-foreground">·</span>
                      <span>{item.city}</span>
                      {item.imported_count > 0 && (
                        <Badge variant="secondary" className="text-[9px] h-4 px-1 ml-auto">
                          +{item.imported_count}
                        </Badge>
                      )}
                      {item.discovered_count === 0 && (
                        <span className="text-muted-foreground text-[10px] ml-auto">无结果</span>
                      )}
                      <span className="text-[10px] text-muted-foreground">{timeAgo(item.completed_at)}</span>
                    </div>
                  ))}
                </div>
              </ScrollArea>
            ) : (
              <p className="text-sm text-muted-foreground text-center py-6">还没有搜索记录</p>
            )}

            {failedTasks.length > 0 && (
              <div className="mt-3 pt-3 border-t space-y-1">
                <div className="text-xs font-medium text-destructive flex items-center gap-1 mb-1">
                  <AlertTriangle className="h-3 w-3" /> 失败任务 ({failedTasks.length})
                </div>
                {failedTasks.slice(0, 10).map((t, i) => (
                  <div key={i} className="flex items-center gap-2 text-xs text-muted-foreground px-2">
                    <XCircle className="h-2.5 w-2.5 text-destructive shrink-0" />
                    <span>{getCountryName(t.country_code)} · {t.city}</span>
                    <span className="text-destructive truncate max-w-[250px]" title={t.error_message || ''}>
                      {(t.error_message || '').slice(0, 50)}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        )}
      </Card>
    </div>
  );
}

// ── Stat Card ──
function PipelineStatCard({ icon, label, value, highlight }: {
  icon: React.ReactNode;
  label: string;
  value: number;
  highlight?: "yellow" | "blue" | "green";
}) {
  const bgClass = highlight === "yellow" ? "bg-yellow-50 dark:bg-yellow-900/10 border-yellow-200 dark:border-yellow-800"
    : highlight === "blue" ? "bg-blue-50 dark:bg-blue-900/10 border-blue-200 dark:border-blue-800"
    : highlight === "green" ? "bg-emerald-50 dark:bg-emerald-900/10 border-emerald-200 dark:border-emerald-800"
    : "border-border";

  return (
    <Card className={bgClass}>
      <CardContent className="py-3 px-3">
        <div className="flex items-center gap-2">
          {icon}
          <div>
            <div className="text-xl font-bold text-foreground">{value.toLocaleString()}</div>
            <div className="text-[10px] text-muted-foreground">{label}</div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}
